"""
T2 RBAC System — Auth Routes (Sample 1)

Evolutionary variant: compact style with a standalone _make_token helper.
Password hashing delegated to middleware.hash_password().
"""

import datetime
import jwt as pyjwt
from flask import Blueprint, request, jsonify, current_app
from models import User
from middleware import hash_password

auth_bp = Blueprint('auth_bp', __name__)


def _make_token(user_id, tenant_id):
    """Build and return a signed JWT string."""
    secret = current_app.config['JWT_SECRET']
    hours = current_app.config['JWT_EXPIRY_HOURS']
    payload = {
        'user_id': user_id,
        'tenant_id': tenant_id,
        'exp': datetime.datetime.utcnow() + datetime.timedelta(hours=hours),
    }
    return pyjwt.encode(payload, secret, algorithm='HS256')


@auth_bp.route('/login', methods=['POST'])
def login():
    body = request.get_json(silent=True) or {}

    username = body.get('username')
    password = body.get('password')

    if not username or not password:
        return jsonify({'status': 'error', 'message': 'Username and password required'}), 400

    user = User.query.filter_by(username=username).first()
    if user is None or user.password_hash != hash_password(password):
        return jsonify({'status': 'error', 'message': 'Invalid credentials'}), 401

    token = _make_token(user.id, user.tenant_id)
    return jsonify({'status': 'ok', 'data': {'token': token}})

"""
T2 RBAC System — Auth Routes (Gen 1, Sample 2)

Login endpoint implementation.

Design decisions (intentional divergences from typical implementations):
- Input validation extracted into a dedicated pure-function that returns structured errors,
  making it easy to extend with additional field-level checks later.
- JWT generation is a standalone helper with explicit parameter validation (guards
  against None user_id/tenant_id and non-positive expiry).
- Every error response includes a human-readable 'error_type' discriminator alongside
  the 'message', so callers can programmatically distinguish error categories without
  fragile string matching.
- Extra defensive checks: whitespace-only username/password is rejected at validation
  time; JWT expiry is clamped to a minimum of 1 hour to prevent accidental zero/negative
  values from producing immediately-expired tokens.
"""

from datetime import datetime, timedelta
from typing import Tuple, Any, Dict, Optional

import jwt as pyjwt
from flask import Blueprint, request, jsonify, current_app

from models import User
from middleware import hash_password

auth_bp = Blueprint('auth_bp', __name__)


# ---------------------------------------------------------------------------
# Pure validation helpers
# ---------------------------------------------------------------------------

class ValidationError:
    """Lightweight structured validation error."""

    __slots__ = ('status_code', 'error_type', 'message')

    def __init__(self, status_code: int, error_type: str, message: str):
        self.status_code = status_code
        self.error_type = error_type
        self.message = message


def validate_login_payload(payload: Any) -> Optional[ValidationError]:
    """
    Validate the raw JSON body of a login request.

    Returns None if valid, or a ValidationError describing the first problem found.
    Checks performed:
      - payload must be a dict
      - 'username' must exist, be a string, and not be whitespace-only
      - 'password' must exist, be a string, and not be whitespace-only
    """
    if not isinstance(payload, dict):
        return ValidationError(
            status_code=400,
            error_type='INVALID_BODY',
            message='Request body must be a JSON object.',
        )

    username = payload.get('username')
    password = payload.get('password')

    if username is None:
        return ValidationError(
            status_code=400,
            error_type='MISSING_FIELD',
            message='Field "username" is required.',
        )
    if not isinstance(username, str):
        return ValidationError(
            status_code=400,
            error_type='INVALID_FIELD',
            message='Field "username" must be a string.',
        )
    if username.strip() == '':
        return ValidationError(
            status_code=400,
            error_type='EMPTY_FIELD',
            message='Field "username" must not be blank or whitespace-only.',
        )

    if password is None:
        return ValidationError(
            status_code=400,
            error_type='MISSING_FIELD',
            message='Field "password" is required.',
        )
    if not isinstance(password, str):
        return ValidationError(
            status_code=400,
            error_type='INVALID_FIELD',
            message='Field "password" must be a string.',
        )
    if password.strip() == '':
        return ValidationError(
            status_code=400,
            error_type='EMPTY_FIELD',
            message='Field "password" must not be blank or whitespace-only.',
        )

    return None


# ---------------------------------------------------------------------------
# JWT helper
# ---------------------------------------------------------------------------

def build_jwt(user_id: int, tenant_id: int, expiry_hours: int) -> str:
    """
    Build a signed JWT containing user_id, tenant_id, and exp claim.

    Defensive measures:
      - Raises ValueError if user_id or tenant_id is None / non-positive.
      - Clamps expiry_hours to a minimum of 1 to avoid immediately-expired tokens.
    """
    if not user_id or not isinstance(user_id, int):
        raise ValueError(f'Invalid user_id: {user_id!r}')
    if not tenant_id or not isinstance(tenant_id, int):
        raise ValueError(f'Invalid tenant_id: {tenant_id!r}')
    if not isinstance(expiry_hours, int) or expiry_hours < 1:
        # Clamp instead of erroring -- prevents accidental misconfiguration
        # from producing a token that expires instantly.
        expiry_hours = max(int(expiry_hours) if expiry_hours else 1, 1)

    secret = current_app.config.get('JWT_SECRET', 'dev-secret-key')
    now = datetime.utcnow()
    payload = {
        'user_id': user_id,
        'tenant_id': tenant_id,
        'exp': now + timedelta(hours=expiry_hours),
        'iat': now,
    }
    return pyjwt.encode(payload, secret, algorithm='HS256')


# ---------------------------------------------------------------------------
# Route
# ---------------------------------------------------------------------------

@auth_bp.route('/login', methods=['POST'])
def login() -> Tuple[Dict, int]:
    """
    Authenticate a user and return a JWT token.

    Request JSON:  {"username": "<str>", "password": "<str>"}
    Success (200): {"status": "ok", "data": {"token": "<jwt-str>"}}
    Errors:        {"status": "error", "error_type": "<str>", "message": "<str>"}
    """
    # --- Step 1: parse and validate payload ---
    payload = request.get_json(silent=True)
    validation_err = validate_login_payload(payload)
    if validation_err is not None:
        return jsonify({
            'status': 'error',
            'error_type': validation_err.error_type,
            'message': validation_err.message,
        }), validation_err.status_code

    username = payload['username']
    password = payload['password']

    # --- Step 2: look up user ---
    user = User.query.filter_by(username=username).first()

    if user is None:
        return jsonify({
            'status': 'error',
            'error_type': 'AUTHENTICATION_FAILED',
            'message': 'The username or password is incorrect.',
        }), 401

    # --- Step 3: verify password ---
    expected_hash = hash_password(password)
    if user.password_hash != expected_hash:
        return jsonify({
            'status': 'error',
            'error_type': 'AUTHENTICATION_FAILED',
            'message': 'The username or password is incorrect.',
        }), 401

    # --- Step 4: generate JWT ---
    try:
        expiry_hours = int(current_app.config.get('JWT_EXPIRY_HOURS', 24))
        token = build_jwt(
            user_id=user.id,
            tenant_id=user.tenant_id,
            expiry_hours=expiry_hours,
        )
    except (ValueError, TypeError) as exc:
        # This should never happen with valid DB data, but we guard against it.
        return jsonify({
            'status': 'error',
            'error_type': 'INTERNAL_ERROR',
            'message': 'Could not generate authentication token. Please contact an administrator.',
        }), 500

    # --- Step 5: return success ---
    return jsonify({
        'status': 'ok',
        'data': {
            'token': token,
        },
    }), 200

