"""
T2 RBAC System -- Document Routes (Sample 2: Gen 1, Developer)

Complete document CRUD with RBAC enforcement.

Design decisions (evolutionary variant -- intentionally different from Sample 1):
- Uses `require_auth` decorator + manual permission checks via g.current_permissions
  instead of the `check_permission` decorator. This allows multi-condition checks
  (e.g., doc.write AND (owner OR doc.write.any)) in a single route handler without
  stacking multiple decorators or calling get_user_permissions redundantly.
- Defensive input validation: title must be a non-empty string, content defaults to
  empty string if omitted. This catches malformed payloads early with clear messages.
- A single `_get_doc_in_tenant()` helper centralises the "fetch doc + verify tenant"
  pattern used by GET /<id>, PUT /<id>, and DELETE /<id>. It returns (doc, error)
  so callers can short-circuit cleanly.
- Serialization helper `_doc_dict()` ensures consistent output shape across all
  endpoints that return a single document.
- Error messages are generic ("Not found", "Permission denied") to avoid leaking
  information about resources in other tenants.

To activate: change app.py import from routes_document to routes_document_sample2.
"""

from flask import Blueprint, request, jsonify, g
from models import Document
from app import db
from middleware import require_auth

document_bp = Blueprint('document_bp', __name__)


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def _has_permission(code):
    """Check if the current user (set by require_auth) has a specific permission."""
    return code in g.current_permissions


def _doc_dict(doc):
    """Serialize a Document model instance to the API response dict."""
    return {
        'id': doc.id,
        'tenant_id': doc.tenant_id,
        'owner_id': doc.owner_id,
        'title': doc.title,
        'content': doc.content,
    }


def _get_doc_in_tenant(doc_id, tenant_id):
    """Fetch a document and verify it belongs to the given tenant.

    Returns (document, error_response) tuple. If the document does not exist
    or belongs to a different tenant, returns (None, 404_response) -- using
    a uniform 404 to avoid leaking cross-tenant resource existence.
    """
    doc = Document.query.get(doc_id)
    if doc is None or doc.tenant_id != tenant_id:
        return None, (jsonify({'status': 'error', 'message': 'Not found'}), 404)
    return doc, None


def _validate_create_payload(data):
    """Validate the request body for document creation.

    Returns (title, content, error_response). If validation fails, title and
    content are None and error_response is populated.
    """
    if not data or not isinstance(data, dict):
        return None, None, (jsonify({'status': 'error', 'message': 'Request body must be JSON'}), 400)

    title = data.get('title')
    content = data.get('content', '')

    if not title or not isinstance(title, str) or not title.strip():
        return None, None, (jsonify({'status': 'error', 'message': 'title is required'}), 400)

    if not isinstance(content, str):
        return None, None, (jsonify({'status': 'error', 'message': 'content must be a string'}), 400)

    return title.strip(), content, None


# ---------------------------------------------------------------------------
# Endpoints
# ---------------------------------------------------------------------------

@document_bp.route('/documents', methods=['GET'])
@require_auth
def list_documents():
    """List all documents belonging to the current user's tenant.

    Requires: doc.read permission.
    """
    if not _has_permission('doc.read'):
        return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    user = g.current_user
    docs = Document.query.filter_by(tenant_id=user.tenant_id).all()
    return jsonify({'status': 'ok', 'data': [_doc_dict(d) for d in docs]})


@document_bp.route('/documents/<int:doc_id>', methods=['GET'])
@require_auth
def get_document(doc_id):
    """Get a single document by ID.

    Requires: doc.read permission + document must belong to current tenant.
    """
    if not _has_permission('doc.read'):
        return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    user = g.current_user
    doc, error = _get_doc_in_tenant(doc_id, user.tenant_id)
    if error:
        return error

    return jsonify({'status': 'ok', 'data': _doc_dict(doc)})


@document_bp.route('/documents', methods=['POST'])
@require_auth
def create_document():
    """Create a new document.

    Requires: doc.write permission.
    tenant_id is taken from the JWT (current user's tenant).
    owner_id is set to the current user.
    """
    if not _has_permission('doc.write'):
        return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    user = g.current_user
    data = request.get_json(silent=True)

    title, content, error = _validate_create_payload(data)
    if error:
        return error

    doc = Document(
        tenant_id=user.tenant_id,
        owner_id=user.id,
        title=title,
        content=content,
    )
    db.session.add(doc)
    db.session.commit()

    return jsonify({'status': 'ok', 'data': _doc_dict(doc)}), 201


@document_bp.route('/documents/<int:doc_id>', methods=['PUT'])
@require_auth
def update_document(doc_id):
    """Update an existing document.

    Requires: doc.write permission AND (user is the owner OR user has doc.write.any).
    Document must belong to the current user's tenant.
    """
    if not _has_permission('doc.write'):
        return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    user = g.current_user
    doc, error = _get_doc_in_tenant(doc_id, user.tenant_id)
    if error:
        return error

    # Ownership check: owner can edit, or anyone with doc.write.any
    if doc.owner_id != user.id and not _has_permission('doc.write.any'):
        return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    data = request.get_json(silent=True)
    if not data or not isinstance(data, dict):
        return jsonify({'status': 'error', 'message': 'Request body must be JSON'}), 400

    # Partial update: only update fields that are provided
    if 'title' in data:
        title = data['title']
        if not title or not isinstance(title, str) or not title.strip():
            return jsonify({'status': 'error', 'message': 'title is required'}), 400
        doc.title = title.strip()

    if 'content' in data:
        content = data['content']
        if not isinstance(content, str):
            return jsonify({'status': 'error', 'message': 'content must be a string'}), 400
        doc.content = content

    db.session.commit()

    return jsonify({'status': 'ok', 'data': _doc_dict(doc)})


@document_bp.route('/documents/<int:doc_id>', methods=['DELETE'])
@require_auth
def delete_document(doc_id):
    """Delete a document.

    Requires: doc.delete permission.
    Document must belong to the current user's tenant (returns 404 otherwise).
    """
    if not _has_permission('doc.delete'):
        return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    user = g.current_user
    doc, error = _get_doc_in_tenant(doc_id, user.tenant_id)
    if error:
        return error

    db.session.delete(doc)
    db.session.commit()

    return jsonify({'status': 'ok', 'data': {'id': doc.id}})

